#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long A,B,C,D;
        scanf("%lld %lld %lld %lld",&A,&B,&C,&D);
        long long len1 = B - A + 1;
        long long len2 = D - C + 1;
        long long start = A > C ? A : C;
        long long end = B < D ? B : D;
        long long overlap = 0;
        if(end >= start) overlap = end - start + 1;
        printf("%lld
", len1 + len2 - overlap);
    }
    return 0;
}

